mapper.select:
select co.id, co.check_in_id, co.elder_id, co.checkout_type, co.checkout_date, co.actual_leave_date, co.reason, co.total_charged, co.total_deducted, co.refund_amount, co.arrears, co.status, e.name as elder_name, e.id_card_no, e.phone, b.bed_number, r.room_number, f.name as floor_name from check_out co left join elder e on co.elder_id = e.id left join check_in ci on co.check_in_id = ci.id left join check_in_cost cic on ci.id = cic.check_in_id left join bed b on cic.bed_id = b.id left join room r on b.room_id = r.id left join floor f on r.floor_id = f.id
and e.name like concat('%', #{elderName}, '%') and co.status = #{status} and co.checkout_type = #{checkoutType}
order by co.create_time desc

mapper.update:
update check_out
check_in_id = #{checkInId}, elder_id = #{elderId}, checkout_type = #{checkoutType}, checkout_date = #{checkoutDate}, actual_leave_date = #{actualLeaveDate}, reason = #{reason}, total_charged = #{totalCharged}, total_deducted = #{totalDeducted}, refund_amount = #{refundAmount}, arrears = #{arrears}, status = #{status}, remark = #{remark}, update_time = #{updateTime}, update_by = #{updateBy},
where id = #{id}
